var prefix = global.get('mqtt_topic_prefix');
if (!prefix) {
    prefix = 'm360/DF/0000';
    global.set('mqtt_topic_prefix', prefix);
}
if (flow.get('ack_timeout_ms') === null || flow.get('ack_timeout_ms') === undefined) {
    flow.set('ack_timeout_ms', 5000);
}
if (flow.get('ack_max_retries') === null || flow.get('ack_max_retries') === undefined) {
    flow.set('ack_max_retries', 3);
}
if (flow.get('nodes_ttl_ms') === null || flow.get('nodes_ttl_ms') === undefined) {
    flow.set('nodes_ttl_ms', 600000);
}
node.status({fill:'green',shape:'dot',text:'prefix='+prefix+' timeout='+flow.get('ack_timeout_ms')+'ms'});
msg.payload = {mqtt_topic_prefix:prefix, ack_timeout_ms:flow.get('ack_timeout_ms'), ack_max_retries:flow.get('ack_max_retries')};
return msg;

// Timeout configurável via flow variable
var TIMEOUT_MS = flow.get('ack_timeout_ms') || 5000;
var MAX_RETRIES = flow.get('ack_max_retries') || 3;
var MQTT_PREFIX = global.get('mqtt_topic_prefix') || 'm360/DF/0000';

var enableSync = flow.get('enable_ack_sync');
if (enableSync === undefined) enableSync = true;

// ─── Mensagens de controle ───────────────────────────────────────
if (msg.topic === 'control') {
    var state = (msg.payload === 'enable' || msg.payload === true);
    flow.set('enable_ack_sync', state);
    if (state) {
        node.status({ fill: 'green', shape: 'dot', text: 'Sincronismo: Ativo' });
    } else {
        node.status({ fill: 'red', shape: 'ring', text: 'Sincronismo: Inativo (Bypass)' });
        context.set('waiting', false);
        context.set('queue', []);
        var t = context.get('timer');
        if (t) { clearTimeout(t); context.set('timer', null); }
    }
    return null;
}

// ─── Helpers ─────────────────────────────────────────────────────

// CORREÇÃO B+C: iniciarItem configura TODO o estado para qualquer item da fila,
// incluindo waiting, targetNode, targetSensor e o timer — independente de onde é chamado.
function iniciarItem(item) {
    context.set('waiting', true);
    context.set('targetNode', item.targetNode);
    context.set('targetSensor', item.targetSensor);
    context.set('retries', 0);
    agendarTimeout(item, 0);
    node.status({
        fill: 'yellow', shape: 'dot',
        text: 'Aguardando ACK nó ' + item.targetNode + ' sensor ' + item.targetSensor
    });
    node.send([item.mqttMsg, null]);
}

function agendarTimeout(item, tentativa) {
    // CORREÇÃO: limpar timer anterior antes de criar novo (evita timers órfãos)
    var t = context.get('timer');
    if (t) { clearTimeout(t); context.set('timer', null); }

    var delay = TIMEOUT_MS * Math.pow(2, tentativa);
    var newTimer = setTimeout(function () {
        if (!context.get('waiting')) return;
        var retries = (context.get('retries') || 0) + 1;
        context.set('retries', retries);

        if (retries < MAX_RETRIES) {
            node.warn('Timeout ACK Nó ' + item.targetNode +
                ' sensor ' + item.targetSensor +
                ' — Tentativa ' + (retries + 1) + '/' + MAX_RETRIES);
            node.send([item.mqttMsg, null]);
            agendarTimeout(item, retries);
        } else {
            context.set('waiting', false);
            context.set('timer', null);
            context.set('retries', 0);
            node.error('Falha definitiva — Nó ' + item.targetNode +
                ' sensor ' + item.targetSensor +
                ' após ' + MAX_RETRIES + ' tentativas');
            node.status({
                fill: 'red', shape: 'ring',
                text: 'Falha nó ' + item.targetNode +
                    ' | fila: ' + (context.get('queue') || []).length
            });
            // Tenta próximo da fila mesmo após falha
            var queue = context.get('queue') || [];
            if (queue.length > 0) {
                var next = queue.shift();
                context.set('queue', queue);
                iniciarItem(next);
            }
            node.send([null, {
                payload:
                    'Erro: Timeout após ' + MAX_RETRIES + ' tentativas — Nó ' + item.targetNode
            }]);
        }
    }, delay);
    context.set('timer', newTimer);
}

// ─── ACK recebido do gateway ──────────────────────────────────────
if (msg.topic === MQTT_PREFIX + '/out') {
    if (!enableSync) return null;

    var data = msg.payload;
    if (typeof data === 'string') {
        try { data = JSON.parse(data); }
        catch (e) {
            node.warn('Erro ao parsear JSON do ACK: ' + e.message);
            return null;
        }
    }
    if (!data || !context.get('waiting')) return null;

    var targetNode = context.get('targetNode');
    var targetSensor = context.get('targetSensor');

    // Três formas de confirmação aceitas:
    //   direction:"ack"         → ACK de transporte publicado pelo gateway (preferencial)
    //   ack:1                   → bit ACK MySensors explícito
    //   command:1 && type:2     → nó devolveu V_STATUS (fallback; type:2 evita falso
    //                             positivo com leituras de sensor do mesmo nó)
    // targetSensor==255: broadcast — aceitar qualquer sensorId do mesmo nó
    var isConfirmation = (
        data.nodeId == targetNode &&
        (targetSensor == 255 || data.sensorId == targetSensor) &&
        (data.direction === 'ack' || data.ack === 1 || (data.command === 1 && data.type === 2))
    );
    if (!isConfirmation) return null;

    // ACK confirmado — limpar estado
    var t = context.get('timer');
    if (t) { clearTimeout(t); context.set('timer', null); }
    context.set('waiting', false);
    context.set('retries', 0);

    var queue = context.get('queue') || [];
    node.log('ACK confirmado — nó ' + targetNode +
        ' sensor ' + targetSensor +
        ' | fila restante: ' + queue.length);
    node.status({
        fill: 'green', shape: 'dot',
        text: 'OK nó ' + targetNode + ' sensor ' + targetSensor +
            ' | fila: ' + queue.length
    });

    // CORREÇÃO C: usa iniciarItem para configurar estado completo do próximo item
    if (queue.length > 0) {
        var next = queue.shift();
        context.set('queue', queue);
        iniciarItem(next);  // configura waiting, targetNode/Sensor e timer
    }

    return [null, { payload: 'Sucesso: Nó ' + targetNode + ' sensor ' + targetSensor + ' confirmou' }];
}

// ─── Novo comando ─────────────────────────────────────────────────
var requestData = msg.payload;
if (typeof requestData === 'string') {
    try { requestData = JSON.parse(requestData); }
    catch (e) {
        node.warn('Erro ao parsear JSON do comando: ' + e.message);
        return [null, { payload: 'Erro: JSON malformado no comando: ' + msg.payload }];
    }
}

var targetNode = (requestData && requestData.nodeId !== undefined) ? requestData.nodeId : 99;
var targetSensor = (requestData && requestData.sensorId !== undefined) ? requestData.sensorId : 255;

var cmdToSend     = requestData.command  !== undefined ? requestData.command  : 1;
var typeToSend    = requestData.type     !== undefined ? requestData.type     : 2;
var payloadToSend = requestData.payload  !== undefined ? String(requestData.payload) : '';
var mqttMsg = {
    topic: MQTT_PREFIX + '/in/' + targetNode + '/' + targetSensor + '/' + cmdToSend + '/0/' + typeToSend,
    payload: payloadToSend
};

// ACK aguardado apenas para C_SET V_STATUS (command=1, type=2) — controle de relé/atuador.
// REPRESENT, FORCE_UPDATE e outros comandos administrativos são enviados sem esperar ACK.
var isRelayCmd = (requestData.command === 1 && requestData.type === 2);
if (!enableSync || targetNode === 255 || requestData.command === 3 || !isRelayCmd) {
    node.status(!enableSync
        ? { fill: 'red', shape: 'ring', text: 'Sincronismo: Inativo (Bypass)' }
        : { fill: 'blue', shape: 'dot', text: 'Enviado: nó ' + targetNode });
    return [mqttMsg, null];
}

var item = { mqttMsg: mqttMsg, targetNode: targetNode, targetSensor: targetSensor };

if (context.get('waiting')) {
    var queue = context.get('queue') || [];
    queue.push(item);
    context.set('queue', queue);
    node.warn('ACK pendente — enfileirado. Fila: ' + queue.length);
    return [null, {
        payload:
            'Ocupado: ACK pendente para Nó ' + context.get('targetNode') +
            '. Enfileirado (posição ' + queue.length + ')'
    }];
}

iniciarItem(item);
return null;

initialize:
context.set('waiting', false);
context.set('queue', []);
context.set('retries', 0);
context.set('timer', null);

