// CORREÇÃO 9: Watchdog proativo - registra último contato do gateway
var now = Date.now();
flow.set('gateway_last_seen', now);
flow.set('gateway_online', true);
node.status({fill:'green', shape:'dot', text:'Online: ' + new Date(now).toLocaleTimeString()});
msg.payload = {status:'ONLINE', ts: now, raw: msg.payload};
